import React, { useRef  } from 'react';
import { GLTFLoader } from "three/examples/jsm/loaders/GLTFLoader";
import { useLoader } from 'react-three-fiber';
import { chairMaterialObjects } from './texture';


export default function Chair(props) {
  let meshObjects = [];  
  const group = useRef();
  const modelPath = 'assets/models/chair.glb'
  const objectNames =  [ "back", "base", "cushions", "legs", "supports"];
  
  const { nodes } = useLoader(GLTFLoader, modelPath)    
  const chairMaterial = chairMaterialObjects();
  
  for (const [i, val] of objectNames.entries()) {
    let geom = nodes[val].geometry;
    let mat = chairMaterial[val];
    meshObjects.push(
      <mesh 
        visible
        position={[0, -2, 0]}
        scale={[1.1, 1.1, 1.1]}
        geometry={ geom }
        material={ mat }
        receiveShadow
        castShadow
        key={i}
      >     
    </mesh>
    )
  }  
  return (
    <group ref={group}>       
      { meshObjects }
    </group>
  );
}