import React from 'react';
import { useTranslation } from 'react-i18next'
import { Element } from 'react-scroll'

import "./Contact.css";
// https://codepen.io/nxworld/pen/OyRrGy?editors=0100
export default function Contact() {
  const { t } = useTranslation() 
  return (
    <Element name="contact">
      <div className="row" id="contact">
        <div className="col-12">
          <h1 id="contact-title" className="title text-center"> {t('contact.title')} </h1>
          <p className="text-center line-height-small"> {t('contact.contactme1')} </p>
          <p className="text-center"> {t('contact.contactme2')} </p>
          <div id="email-input" className="input-group input-group-lg mx-auto py-4">
            <div className="input-group-prepend">
              <span className="input-group-text" id="inputGroup-sizing-lg">
                <a href="mailto:contact@dibr-studio.com" className="mailto-text" >
                  mailto:
                </a>
                <a href="mailto:contact@dibr-studio.com" className="mailto-arrow" >
                  <span className="fa fa-arrow-right" aria-hidden="true"></span>
                </a>
              </span>
            </div>
            <input  type="email" value="contact@dibr-studio.com" className="form-control" aria-label="Large" aria-describedby="inputGroup-sizing-sm" readOnly />
          </div>
        </div>
      </div>
    </Element>
  )  
}