import './Footer.css'
import React from 'react';

import { Link } from 'react-scroll';

export default function Footer() {
  return (
    <footer className="py-5">
      <div className="row">
        <div className="col-12 col-md-3 pb-3">
          <div className="logo-footer">
            Dibr Studio
            <small className="d-block mb-3 text-muted">© 2020</small>
          </div>
        </div>
        <div className="col-12 col-md-2 pb-3 ml-3 ml-md-0">
          <div className="footer-line-separator"></div>
          <h5 className="pb-3"> Menu </h5>
          <ul>
            <li className="pb-2">
              <Link className="nav-link blur" to="work" spy={true} smooth={true} duration={1000}>
                Work
              </Link>
            </li>
            <li className="pb-2">
              <Link className="nav-link blur" to="services" spy={true} smooth={true} duration={1000}>
                Service
              </Link>
            </li>
            <li className="pb-2">
              <a href="#" className="nav-link blur"> Blog </a>
            </li>
            <li className="pb-2">
              <Link className="nav-link blur" to="contact" spy={true} smooth={true} duration={1000}>
                Contact
              </Link>
            </li> 
          </ul> 
        </div>
        <div className="col-12 col-md-4 pb-3 ml-3 ml-md-0">
          <div className="footer-line-separator"></div>
          <h5 className="pb-3">Send Me a Message </h5>
          <ul className="list-unstyled">       
            <li className="icon pb-2">
              <div className="circle-icon icon-lg">           
                <i className="fa fa-phone fa-lg"></i>
              </div>       
              +62 8131939789
            </li>
            <li className="icon pb-2">
              <div className="circle-icon icon-sm">
                <i className="fa fa-envelope" aria-hidden="true"></i>
              </div>
              <div className="email"> contact@dibr-studio.com </div>
            </li>
          </ul>
        </div>
        <div className="col-12 col-md-3 pb-3 ml-3 ml-md-0">
          <div className="footer-line-separator"></div>
          <h5 className="pb-3"> Follow us on: </h5>
          <ul className="instagram">          
            <a href="#">
            <li className="icon">                     
              <div className="circle-icon icon-lg">               
                <i className="fa fa-instagram fa-lg"></i>        
              </div> 
              <div className="instagram-text"> Instagram </div>
            </li>
            </a>
          </ul>
        </div>
      </div>
    </footer>   
  )
}

