import * as THREE from 'three';


let woodMaterial = {
  type: 'texture',
  texturePath: 'assets/image/wood_.jpg',
  size: [2, 2, 2],
  shininess: 60
}

// let denimMaterial = {
//   type: 'texture',
//   texturePath: 'assets/image/denim_.jpg',
//   size: [3, 3, 3],
//   shininess: 0
// }

let greenColorMaterial = {
  type: 'color',
  color: 0x4C8A67
}

// let grayColorMaterial = {
//   type: 'color',
//   color: 0xACB4B9
// }


function setMaterialTexture(textureMaterials) {
  let material;
  let loader = new THREE.TextureLoader();
  let shininess = textureMaterials.shininess ? textureMaterials.shininess : 10;
  
  // set loader cross origin
  loader.crossOrigin = "";
  if (textureMaterials.type === 'texture') {
    let textr = loader.load(textureMaterials.texturePath)
    textr.anisotropy = 16;
    // set the "color space" of the texture
    // textr.encoding = THREE.sRGBEncoding;

    textr.repeat.set( textureMaterials.size[0], textureMaterials.size[1], textureMaterials.size[2]);
    textr.wrapS = THREE.RepeatWrapping;
    textr.wrapT = THREE.RepeatWrapping;
    material = new THREE.MeshPhongMaterial( {
      map: textr,
      shininess: shininess
    });
    material.map.minFilter = THREE.LinearFilter;
  } else if (textureMaterials.type === 'color') {
    material = new THREE.MeshPhongMaterial( {
      color: textureMaterials.color,
      shininess: shininess
    })    
  }
  return material
}


export const chairMaterialObjects = () => {
  return {
    back: setMaterialTexture(woodMaterial),
    base: setMaterialTexture(woodMaterial),
    cushions: setMaterialTexture(greenColorMaterial),
    legs: setMaterialTexture(woodMaterial),
    supports: setMaterialTexture(woodMaterial)
  }
}