import React, { useRef, Suspense } from 'react';

import * as THREE from 'three';
import { OrbitControls } from 'three/examples/jsm/controls/OrbitControls'
import { Canvas, extend, useFrame, useThree } from 'react-three-fiber';
import Chair from './chair';

extend({ OrbitControls })


// draw plane
function Floor(props) {
  const PLANE_COLOR = 0xf1f1f1;  
  return (
    <mesh 
      visible
      geometry={ new THREE.PlaneGeometry(5000, 5000, 1, 1)}
      material={ new THREE.MeshPhongMaterial({
        color: PLANE_COLOR,
        shininess: 1
      })}
      rotation-x={ THREE.Math.degToRad(-90) }
      position={[0, -2, 0]}
      receiveShadow
    />
  )
}



export default function Model() {
  const LIGHT_COLOR = 0xffffff;
  const HEMIS_GROUND_COLOR = 0x5f5c5c;
  const BACKGROUND_COLOR = '#E0E0E0';

  const setCamera = {
    position: [0, 10, 15],
    fov: 75,
    near: .1,    
    far: 1000
  }
  const CameraControls = () => {
    const {
      size,
      camera,
      gl: { domElement }
    } = useThree();    
    let control = useRef();
    console.log(size);
    useFrame((state) => control.current.update());
    return <orbitControls enableZoom={false} minPolarAngle={ THREE.Math.degToRad(60) } maxPolarAngle={ THREE.Math.degToRad(90) } ref={control} args={[camera, domElement]} />;
  }
  
  return (
   <Canvas 
    shadowMap
    camera={ setCamera }
    gl={{ antialias: true }}  
    onCreated={({ gl, scene }) => {
      scene.background = new THREE.Color(BACKGROUND_COLOR)
    }}    
   >
    <CameraControls />
    <hemisphereLight color={ LIGHT_COLOR } groundColor= { HEMIS_GROUND_COLOR } intensity={0.61} />
    <directionalLight 
      color={ LIGHT_COLOR } 
      intensity={0.54} 
      position={[10, 8, 5]}
      castShadow
      shadow-mapSize-width={1024}
      shadow-mapSize-height={1024}
      shadow-camera-far={50}
      shadow-camera-left={-10}
      shadow-camera-right={10}
      shadow-camera-top={10}
      shadow-camera-bottom={-10}
      />    
    <Floor />      
    <Suspense fallback={null}>
      <Chair />
    </Suspense>
  </Canvas>
  )
}