import * as PIXI from 'pixi.js'
import { Sprite, Stage } from 'react-pixi-fiber';
import React, { useEffect, useState, useRef } from 'react';

import bg from './monumen.jpg';
import bgMap from './monumen-map.jpeg';

import bgMid from './monumen-mid.jpg';
import bgMapMid from './monumen-map-mid.jpg';

import bgSmall from './monumen-small.jpg';
import bgMapSmall from './monumen-map-small.jpeg';

const OPTIONS = { 
  height: window.innerHeight,
  width: window.innerWidth
}

// TASK: resize window
// TASK: optimize on mobile
//    touchmove event
//    new images for mobile

function Banner() {    
  let mouseRef = useRef(null);
  const [ filters, setFilters ] = useState([]);
  const [ size, setSize ] = useState(OPTIONS)  
  const getOverlay = () => {    
    if (size.width <= 500) {
      return PIXI.Texture.from(bgMapSmall)
    } else if (size.width > 500 && size.width < 1000) {
      return PIXI.Texture.from(bgMapMid)
    } else {
      return PIXI.Texture.from(bgMap)
    }    
  }

  const getBackground = () => {
    if (size.width <= 500) {
      console.log('test')
      return PIXI.Texture.from(bgSmall)
    } else if (size.width > 500 && size.width < 1000) {
      return PIXI.Texture.from(bgMid)
    } else {
      return PIXI.Texture.from(bg)
    }
  }

  useEffect(() => {
    setFilters([  new PIXI.filters.DisplacementFilter(mouseRef.current) ])    
  }, [])

  useEffect(() => {    
    const handleResize = () => {      
      console.log(window.innerHeight, window.innerWidth)
      setSize({ height: window.innerHeight, width: window.innerWidth })
    }
    const mouseMove = (e) => {        
      let x = ( window.innerWidth / 2 - e.clientX ) / 35;
      let y = ( window.innerHeight / 2 - e.clientY ) / 25;
      if (filters.length > 0 ) {        
        let filter = filters.slice()[0]
        filter.scale.x = x;
        filter.scale.y = y;
        setFilters( [filter] )
      }
    }
    window.addEventListener('resize', handleResize)
    window.addEventListener('mousemove', mouseMove)
    // window.addEventListener('load', () => {
    //   let filter = new PIXI.filters.DisplacementFilter(mouseRef.current);
    //   setFilters([ filter ])      
    // })

    return () => {
      window.removeEventListener('mousemove', mouseMove) 
      window.removeEventListener('resize', handleResize) 
    }
  })

  return (   
    <div id="background">
      <Stage options={ size }  filters={ filters } >
          <Sprite texture={ getBackground() } height={ size.height }  width={ size.width } />
          <Sprite
            ref={ mouseRef }
            width={ size.width }
            height={ size.height }  
            texture={ getOverlay() } 
          />
      </Stage>
    </div>
  )
}


export default Banner;